import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Internal config type (shared with the provider factory)
// ---------------------------------------------------------------------------

export interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Response schema for the fictional PixelArt API
// The API returns a DALL-E-style JSON envelope with base64-encoded images.
// ---------------------------------------------------------------------------

const pixelartImageResponseSchema = z.object({
  created: z.number(),
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

// ---------------------------------------------------------------------------
// Error schema – the PixelArt API wraps errors in { error: { message } }
// ---------------------------------------------------------------------------

const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().optional(),
    code: z.string().nullish(),
  }),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: zodSchema(pixelartErrorSchema),
  errorToMessage: data => data.error.message,
});

// ---------------------------------------------------------------------------
// PixelArtImageModel
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * PixelArt's API only supports generating one image per call.
   */
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      files,
      mask,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // ------------------------------------------------------------------
    // Warn about features the PixelArt API does not support
    // ------------------------------------------------------------------

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'PixelArt does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support seeded generation.',
      });
    }

    if (files != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support image editing or img2img.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting.',
      });
    }

    // ------------------------------------------------------------------
    // Resolve final parameter values
    // Model-level settings act as defaults; call-time providerOptions
    // can override them.
    // ------------------------------------------------------------------

    const pixelartOptions =
      (providerOptions.pixelart as Record<string, unknown> | undefined) ?? {};

    const resolvedSize =
      (pixelartOptions.size as string | undefined) ??
      size ??
      this.settings.size;

    const resolvedStyle =
      (pixelartOptions.style as string | undefined) ?? this.settings.style;

    const resolvedPixelDensity =
      (pixelartOptions.pixel_density as number | undefined) ??
      (pixelartOptions.pixelDensity as number | undefined) ??
      this.settings.pixelDensity;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // ------------------------------------------------------------------
    // POST to the PixelArt image generation endpoint
    // ------------------------------------------------------------------

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(resolvedSize != null ? { size: resolvedSize } : {}),
        ...(resolvedStyle != null ? { style: resolvedStyle } : {}),
        ...(resolvedPixelDensity != null
          ? { pixel_density: resolvedPixelDensity }
          : {}),
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        zodSchema(pixelartImageResponseSchema),
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    // ------------------------------------------------------------------
    // Return the standardised ImageModelV3 response
    // ------------------------------------------------------------------

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(() => ({
            created: response.created,
            ...(resolvedStyle != null ? { style: resolvedStyle } : {}),
            ...(resolvedPixelDensity != null
              ? { pixelDensity: resolvedPixelDensity }
              : {}),
          })),
        },
      },
    };
  }
}

