import {
  type ImageModelV3,
  NoSuchModelError,
  type ProviderV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
import { VERSION } from './version';

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

/**
 * Configuration options for the PixelArt provider.
 */
export interface PixelArtProviderSettings {
  /**
   * PixelArt API key.
   * Defaults to the value of the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Additional HTTP headers to include with every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom `fetch` implementation. Can be used as middleware to intercept
   * requests or to provide a test double.
   */
  fetch?: FetchFunction;
}

/**
 * The PixelArt provider interface.
 * Only image generation is supported; calls to `languageModel` or
 * `embeddingModel` will throw a `NoSuchModelError`.
 */
export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   *
   * @param modelId  - The PixelArt model to use (e.g. `"pixelart-v1"`).
   * @param settings - Optional model-level defaults (size, style, pixelDensity).
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Alias for `image()`.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

/**
 * Creates a configured PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 *
 * const pixelart = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 * const model = pixelart.imageModel('pixelart-v1', { style: 'pixel', pixelDensity: 8 });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings: PixelArtImageSettings = {},
  ) =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? DEFAULT_BASE_URL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // PixelArt only supports image generation.
  const unsupportedLanguageModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
  };

  const unsupportedEmbeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  const provider: PixelArtProvider = {
    specificationVersion: 'v3',

    // Image generation — the only supported capability
    image: createImageModel,
    imageModel: createImageModel,

    // Unsupported capabilities
    languageModel: unsupportedLanguageModel,
    embeddingModel: unsupportedEmbeddingModel,
    textEmbeddingModel: unsupportedEmbeddingModel,
  };

  return provider;
}

/**
 * Default PixelArt provider instance.
 * Reads `PIXELART_API_KEY` from the environment automatically.
 */
export const pixelart = createPixelArt();

